VALUES
  ('dietitian-moex-10794', 'dietitian', 'dietitian-moex-094-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '關於特殊營養素在創傷病人之應用，以下敘述何者不正確？ 短鏈脂肪酸可作為腸道細胞（colonocyte）之能量來源，防止腸道萎縮 補充BCAA可減緩胺基酸自肌肉組織流失 glutamine為一氧化氮（NO）之前驅物質，可活化體內之免疫反應 arginine之添加有助於傷口癒合', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "8fcc596fc6ec", "answer_pdf_sha1": "c6d0f373e8c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10795', 'dietitian', 'dietitian-moex-094-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '關於nephrotic syndrome以下敘述何者不正確？ 因腎絲球對蛋白質之通透性變大，因此造成蛋白質流失  需給予高蛋白質飲食以彌補蛋白質之流失 需限制鈉之攝取    會有高膽固醇血症', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "8fcc596fc6ec", "answer_pdf_sha1": "c6d0f373e8c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10796', 'dietitian', 'dietitian-moex-094-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', 'DASH飲食適用於何種疾病之防治？ 高血糖  高血脂  高血壓  高尿酸', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "8fcc596fc6ec", "answer_pdf_sha1": "c6d0f373e8c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10797', 'dietitian', 'dietitian-moex-094-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '在創傷後剛進入高亢期（Flow phase）時之代謝狀況，以下敘述何者不正確？ 身體處於負氮平衡  急性期蛋白質合成增加  抑制糖質新生作用  增加catecholamine之分泌', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "8fcc596fc6ec", "answer_pdf_sha1": "c6d0f373e8c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10798', 'dietitian', 'dietitian-moex-094-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '身體處在代謝壓力下與飢餓狀態下之比較，以下敘述何者不正確？ 當承受代謝壓力時RMR較飢餓時為高  代謝壓力時酮體之產生量較飢餓時為高 飢餓時之呼吸商通常較代謝壓力時為低  代謝壓力時肝臟蛋白質之合成量較飢餓時為高', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "8fcc596fc6ec", "answer_pdf_sha1": "c6d0f373e8c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10799', 'dietitian', 'dietitian-moex-094-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '以下何者不是腎臟之功能？ 分泌renin    活化維生素D 分泌aldosterone    產生紅血球生成素（erythropoietin）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "8fcc596fc6ec", "answer_pdf_sha1": "c6d0f373e8c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10800', 'dietitian', 'dietitian-moex-094-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '對有慢性阻塞性肺疾病（COPD）患者，以下敘述何者不正確？ 吸菸是造成COPD的主要原因  熱量需求通常較正常人高 提高醣類攝取可減輕呼吸之負擔  常有血氧過低的情形', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "8fcc596fc6ec", "answer_pdf_sha1": "c6d0f373e8c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10801', 'dietitian', 'dietitian-moex-094-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '以下何種試驗與胰臟功能之評估無關？ glucose tolerance test  tryptophan loading test  secretin stimulation test  72-hr stool fat test', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "8fcc596fc6ec", "answer_pdf_sha1": "c6d0f373e8c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10802', 'dietitian', 'dietitian-moex-094-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '關於嬰幼兒急性腹瀉之處置以下何者正確？ 應避免進食以免對腸道造成刺激  以全靜脈供給營養較適當 應積極補充水分和電解質    電解質中以鎂、磷、氯之補充為最重要 （請接背面）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "8fcc596fc6ec", "answer_pdf_sha1": "c6d0f373e8c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10803', 'dietitian', 'dietitian-moex-094-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '年第一次專門職業及技術人員高等暨普通考試醫事人員、 全一張 （背面） 中醫師、心理師、呼吸治療師、營養師、獸醫人員考試試題 等    別 ：高等考試 類    科 ：營養師 科    目 ：膳食療養學', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "8fcc596fc6ec", "answer_pdf_sha1": "c6d0f373e8c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 94, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
